def lcs_of_three(str1, str2, str3):
    # Create a 3D array to store the lengths of common subsequences
    dp = [[[0 for _ in range(len(str3) + 1)] for _ in range(len(str2) + 1)] for _ in range(len(str1) + 1)]

    # Fill the dp array in a bottom-up manner
    for i in range(1, len(str1) + 1):
        for j in range(1, len(str2) + 1):
            for k in range(1, len(str3) + 1):
                # If the current characters in all three strings are the same, 
                # then the length of the common subsequence is one more than the 
                # length of the common subsequence without the current characters
                if str1[i - 1] == str2[j - 1] == str3[k - 1]:
                    dp[i][j][k] = dp[i - 1][j - 1][k - 1] + 1
                # If the current characters are different, then the length of the 
                # common subsequence is the maximum of the lengths of the common 
                # subsequences without the current character in any of the strings
                else:
                    dp[i][j][k] = max(dp[i - 1][j][k], dp[i][j - 1][k], dp[i][j][k - 1])

    # Reconstruct the longest common subsequence from the dp array
    lcs = []
    i, j, k = len(str1), len(str2), len(str3)
    while i > 0 and j > 0 and k > 0:
        # If the current characters in all three strings are the same, 
        # then the current character is part of the longest common subsequence
        if str1[i - 1] == str2[j - 1] == str3[k - 1]:
            lcs.append(str1[i - 1])
            i -= 1
            j -= 1
            k -= 1
        # If the current characters are different, then move to the cell with the 
        # maximum value in the previous row
        elif dp[i - 1][j][k] >= dp[i][j - 1][k] and dp[i - 1][j][k] >= dp[i][j][k - 1]:
            i -= 1
        elif dp[i][j - 1][k] >= dp[i - 1][j][k] and dp[i][j - 1][k] >= dp[i][j][k - 1]:
            j -= 1
        else:
            k -= 1

    # Return the longest common subsequence in the correct order
    return ''.join(reversed(lcs))
