def count_Substrings(s):
    """
    Counts the number of substrings in the given string where the sum of digits equals the length of the substring.

    Args:
        s (str): The input string.

    Returns:
        int: The number of substrings with the sum of digits equal to their length.
    """
    def is_digit(c):
        """Checks if a character is a digit."""
        return c.isdigit()

    def sum_of_digits(substring):
        """Calculates the sum of digits in a substring."""
        return sum(int(c) for c in substring if is_digit(c))

    count = 0
    for length in range(1, len(s) + 1):
        for i in range(len(s) - length + 1):
            substring = s[i:i + length]
            if sum_of_digits(substring) == length:
                count += 1
    return count
